parameters.jsonBody:
={{
$fromAI(
  'final_payload',
  `
You are generating a JSON payload for booking creation.
Insert values STRICTLY following the variable descriptions that you need to get from "Get get services by staff_name" tool:

VARIABLES:
- $json.staff_id → ID of the selected staff member.
- $json.service_id → ID of the service the client chose.
- $json.people_count → number of people in the appointment.
- $json.client_phone → $json.body.user_phone.
- $json.client_name → full name of the client.
- $json.datetime → ISO date+time for appointment start, example: 2025-12-04T10:00:00.
- $json.seance_length → appointment length in seconds.

Now create valid JSON:

{
  "staff_id": "${$json.staff_id}",
  "services": [
    {
      "id": "${$json.service_id}",
      "amount": ${$json.people_count}
    }
  ],
  "client": {
    "phone": "${$json.client_phone}",
    "name": "${$json.client_name}"
  },
  "datetime": "${$json.datetime}",
  "seance_length": "${$json.seance_length}",
  "comment": "ЗАПИСЬ СДЕЛАНА ЧЕРЕЗ БОТА!!!"
}
`,
'string'
)
}}

parameters.url:
={{
$fromAI(
  'final_payload',
  `
Return ONLY this URL, nothing else. Use date in ISO format. Example: 2025-12-10T12:00:00.
https://api.alteg.io/api/v1/book_staff/1097365?datetime=${$json.datetime}
`,
  'string'
)
}}

